from typing import Dict, Any, Mapping


def _sync_display_name(user: Dict[str, Any], name: str) -> None:
    """Set name and keep display_name in sync."""
    user["name"] = name
    user["display_name"] = name


def update_profile(user: Dict[str, Any], changes: Mapping[str, Any]) -> Dict[str, Any]:
    """Update user profile fields from changes dict.

    Invariant: display_name must always equal name.
    Unknown keys are ignored. Explicit changes to display_name are ignored to
    preserve the invariant; use 'name' to update both fields.
    """
