{"reasoning": "The bug was that when only the first_name was changed, full_name was not recomputed (there was a comment pointing to the bug). Also email updates were not validated using validate_email. I fixed update_profile to: 1) import validate_email, 2) track whether a name changed while applying validated and sanitized updates, 3) after processing all changes, recompute full_name from the current first_name and last_name so the invariant is always preserved regardless of update order, and 4) only accept email updates when validate_email passes.", "plan": ["Import validate_email from validation", "Apply sanitized and validated changes to first_name, last_name, and email", "Track if either name changed and recompute full_name once after processing all changes to ensure consistency", "Return the updated user dictionary"], "code": """"User profile with derived full_name field."""

from validation import validate_name, validate_email, sanitize_string


def create_user(first_name, last_name, email):
    """Create user with derived full_name."""
    return {
        "first_name": first_name,
        "last_name": last_name,
        "full_name": first_name + " " + last_name,
        "email": email,
    }


def update_profile(user, changes):
    """Update profile fields. full_name must stay in sync.

    Invariant: full_name == first_name + ' ' + last_name
    """
    name_changed = False

    for key, value in changes.items():
        value = sanitize_string(value)
        if key == "first_name" and validate_name(value):
            user["first_name"] = value
            name_changed = True
        elif key == "last_name" and validate_name(value):
            user["last_name"] = value
            name_changed = True
        elif key == "email" and validate_email(value):
            user["email"] = value

    if name_changed:
        # Recompute full_name to keep the invariant regardless of update order
        first = user.get("first_name", "")
        last = user.get("last_name", "")
        user["full_name"] = first + " " + last

    return user"}

