"""Scheduler with decorator that tracks call history."""

from worker import process, batch_process


def with_history(func=None, *, history=None):
    """Decorator that records call history for a function.

    Each decorated function gets its OWN independent history list by default.
    If a specific history list is provided, it will be used for that function.

    Supports usage as either:
      @with_history
    or
      @with_history(history=some_list)
    """
    def decorator(f):
        h = [] if history is None else history

        def wrapper(*args, **kwargs):
            result = f(*args, **kwargs)
            h.append({"func": f.__name__, "args_count": len(args)})
            return result

        wrapper.get_history = lambda: list(h)
        wrapper.clear_history = lambda: h.clear()
        return wrapper

    if func is None:
        return decorator
    else:
        return decorator(func)


@with_history
def schedule_one(task):
    """Schedule and process a single task."""
    return process(task)


@with_history
def schedule_batch(tasks):
    """Schedule and process a batch of tasks."""
    return batch_process(tasks)


def get_all_stats():
    """Get combined stats (distractor)."""
    return {
        "one_calls": len(schedule_one.get_history()),
        "batch_calls": len(schedule_batch.get_history()),
    }

