"""Batch processor with two effects per item."""

import metrics


def reset():
    """Reset metrics via the metrics module."""
    metrics.reset()


def process_batch(items):
    """For each item: increment counter AND emit event."""
    for item in items:
        # First effect: update the global counter
        metrics.increment(item["value"])
        # Second effect: record an event capturing the current counter
        metrics.emit_event(item["id"], item["value"])
    return len(items)


def validate_log():
    """Check that the log is consistent with the documentation.

    Validation performed:
      - For each event, the stored 'counter' must equal the running total
        of event values up to and including that event.
      - The final running total must equal metrics.get_counter().

    Returns True if the log is consistent, False otherwise.
    """
    events = metrics.get_events()
    running = 0
    for e in events:
        running += e.get("value", 0)
        if e.get("counter") != running:
            return False
    return running == metrics.get_counter()


def get_summary():
    """Return processing summary for display purposes."""
    return {
        "processed_count": len(metrics.get_events()),
        "counter": metrics.get_counter(),
    }"}

