def send_with_retry(msg, max_retries=2, fail_first=False):
    """Retry send on transient errors. Return on success, raise after exhausting retries."""
    last_exc = None
    for attempt in range(max_retries):
        try:
            return send(msg, fail_first=fail_first)
        except ConnectionError as e:
            last_exc = e
            if attempt == max_retries - 1:
                # Exhausted retries; propagate the last error
                raise
            # otherwise, retry
            continue


