from flags import is_enabled


def compute_price(base, qty, use_new_pricing=None):
    """
    Compute price. If use_new_pricing is None, consult the global flag.
    Otherwise, the boolean override determines which pricing version to use.
    """
    if use_new_pricing is None:
        enabled = is_enabled("new_pricing")
    else:
        enabled = bool(use_new_pricing)

    if enabled:
        return _v2_price(base, qty)
    return _v1_price(base, qty)


def _v1_price(base, qty):
    return base * qty


def _v2_price(base, qty):
    discount = 0.1 if qty >= 10 else 0
    return base * qty * (1 - discount)


def get_pricing_version(use_new_pricing=None):
    if use_new_pricing is None:
        enabled = is_enabled("new_pricing")
    else:
        enabled = bool(use_new_pricing)
    return "v2" if enabled else "v1"


