import random
from models import Account
from ledger import record_debit, record_credit, record_transfer_attempt
from audit import emit_transfer_event, emit_failure_alert


class TransferError(RuntimeError):
    def __init__(self, msg, debited=False, credited=False):
        super().__init__(msg)
        self.debited = debited
        self.credited = credited


def validate_transfer(sender, amount):
    if amount <= 0:
        raise ValueError("amount must be positive")
    if sender.balance < amount:
        raise ValueError("insufficient funds")


def _core_transfer(sender, receiver, amount):
    """
    Core transfer logic without any observability (ledger/audit) side-effects.
    Returns a dict indicating which steps completed. May raise TransferError
    to indicate a transient failure during the credit phase, preserving which
    steps had completed.
    """
    debited = False
    credited = False
    # perform debit
    sender.balance -= amount
    debited = True

    # simulate transient failure that can occur during credit
    if random.random() < 0.3:
        # raise an error and indicate debit happened but credit did not
        raise TransferError("transient failure during credit", debited=debited, credited=credited)

    # perform credit
    receiver.balance += amount
    credited = True
    return {"debited": debited, "credited": credited}


def execute_transfer(sender, receiver, amount):
    # validation is part of business logic
    validate_transfer(sender, amount)

    # observability: record the attempt
    record_transfer_attempt(sender.account_id, receiver.account_id, amount)

    try:
        result = _core_transfer(sender, receiver, amount)
    except TransferError as e:
        # move all observability/emitting logic here: record what completed and emit alerts
        if getattr(e, "debited", False):
            record_debit(sender.account_id, amount)
        if getattr(e, "credited", False):
            record_credit(receiver.account_id, amount)

        emit_failure_alert(sender.account_id, receiver.account_id, amount, e)
        # re-raise to preserve original error behavior
        raise

    # if we reach here the transfer completed successfully
    if result.get("debited"):
        record_debit(sender.account_id, amount)
    if result.get("credited"):
        record_credit(receiver.account_id, amount)

    emit_transfer_event(sender.account_id, receiver.account_id, amount)

